(window.webpackJsonp=window.webpackJsonp||[]).push([[208],{719:function(t,e,n){"use strict";n.r(e);var s=n(3),l=Object(s.a)({},(function(){var t=this,e=t.$createElement,n=t._self._c||e;return n("ContentSlotsDistributor",{attrs:{"slot-key":t.$parent.slotKey}},[n("p",[t._v("中国经济网8月26日讯 (记者 庞彩霞) 记者获悉，中国移动广东公司(以下简称“广东移动”)组织技术力量进行攻关，成功研制出全球首创的手机病毒侦测技术，并以此为基础构建新一代的手机病毒防治体系，在网络侧实现对手机病毒的主动侦测，并在终端侧进行查杀，为用户打造绿色安全的手机使用环境。")]),t._v(" "),n("p",[t._v("中国经济网记者了解到，广东移动构筑的手机病毒防治体系包括“手机恶意软件多维度侦测系统”和终端侧云查杀软件“杀毒先锋”。其中，“手机恶意软件多维度侦测系统”采用全球首创的恶意软件行为多维度分析算法及双引擎侦测技术(恶意软件行为分析引擎+病毒体扫描引擎)，不仅能侦测病毒库中已有的病毒和木马，而且能侦测病毒库中没有的疑似新病毒、新木马和手机内置后门等恶意软件，并通过网络封堵，有效遏制手机恶意软件的大规模蔓延。与业界产品比较，该系统在侦测方面具有手段全、范围广、能力强、效率高四大优势。截至2011年8月，该系统共发现流行的活跃手机恶意软件537个，其中先于业界发现的恶意软件占59%。该系统已通过相关机构组织的技术成果鉴定，鉴定结论为“国际首创”。由于应用效果显著，该系统还获得了2010年度中国通信学会信息安全应用奖等诸多奖项。")]),t._v(" "),n("p",[t._v("作为广东移动手机病毒防治体系的另一重要组成部分，终端侧云查杀软件“杀毒先锋”可以进一步清除终端侧的恶意软件，开创了以移动运营商为主导的手机杀毒新模式。据悉，“杀毒先锋”可通过与云端服务结合，在移动互联网上进行分析并主动发现手机中毒情况，并在终端侧对病毒进行精准查杀，形成了完善的“网络查毒，终端杀毒”的病毒防治体系。")]),t._v(" "),n("p",[t._v("日前，这两大自主研发产品已通过了国家计算机病毒防治产品检验中心的检测，并取得了手机病毒防治产品检验合格证。广东移动成为全国第一家也是目前唯一一家同时取得网络侧和终端侧手机病毒防治产品合格证的企业。此外，该公司已取得了由公安部授予的“杀毒先锋”软件的“安全专用产品销售许可证”，从而具备了销售该杀毒产品及开展手机病毒研判、预警等相关安全服务的资质，成为国内第一家也是目前唯一一家具备以上资质的运营商。")]),t._v(" "),n("p",[t._v("广东移动相关负责人表示，公司近期将开展“杀毒先锋”产品的试商用工作，以兑现“免费为客户提供一款手机杀毒软件”的承诺，为用户的手机安全及打造“绿色网络”保驾护航。")])])}),[],!1,null,null,null);e.default=l.exports}}]);